import{_ as o,c as a,o as t,ai as n}from"./chunks/framework.CM7c3k__.js";const d=JSON.parse('{"title":"KubeCon+CloudNativeCon Recap","description":"","frontmatter":{"title":"KubeCon+CloudNativeCon Recap","date":"2026-04-02","banner":"assets/blog/20260402_kubecon_recap_banner.svg","authors":["neonephos-team"],"tags":["2026","news","kubecon"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20260402_kubecon_recap.md","filePath":"blog/20260402_kubecon_recap.md"}'),r={name:"blog/20260402_kubecon_recap.md"};function s(i,e,h,l,u,c){return t(),a("div",null,e[0]||(e[0]=[n('<h1 id="kubecon-cloudnativecon-recap" tabindex="-1">KubeCon+CloudNativeCon Recap <a class="header-anchor" href="#kubecon-cloudnativecon-recap" aria-label="Permalink to &quot;KubeCon+CloudNativeCon Recap&quot;">​</a></h1><p>One year past our grand foundation <a href="https://www.youtube.com/watch?v=57koOOg0f5M&amp;list=PLj6h78yzYM2Of6psbKjeZxZIHjycSYoYF&amp;index=1" target="_blank" rel="noreferrer">launch announcement at the KubeCon+CloudNativeCon &#39;25</a>, it was once again time to meet our peers at the &#39;26 edition of one of the most anticipated events in the cloud native scene. Now, equipped with the fruits of our labor from all these past months, we did not arrive with only grand plans but presented a concrete vision and live demonstrations. Let us break down how below:</p><h2 id="neonephos-booth" tabindex="-1">NeoNephos Booth <a class="header-anchor" href="#neonephos-booth" aria-label="Permalink to &quot;NeoNephos Booth&quot;">​</a></h2><p>Our booth served as our permanent <em>flagpole in the sand</em> amd presented the most initimate way for people to learn about NeoNephos. Thanks to the continuous staffing provided by representatives of our projects, KubeCon attendees were exposed to hands-on demonstrations of some of our projects and could directly ask questions. Many great discussions arose and relationships have formed thanks to this booth. We will be catching up on some of these discussions for sure!</p><h2 id="talks" tabindex="-1">Talks <a class="header-anchor" href="#talks" aria-label="Permalink to &quot;Talks&quot;">​</a></h2><p>We held many presentations, not only at the <a href="https://neonephos.org/events/2026_03_23_KubeCon_Europe" target="_blank" rel="noreferrer">KubeCon</a> itself but also <a href="https://neonephos.org/events/2026_03_23_Open_Sovereign_Cloud_Day" target="_blank" rel="noreferrer">the adjacent Open Sovereign Cloud Day</a>. Most importantly, we had multiple companies involved in these, highlighting our belief in cross-company collaboration.</p><h2 id="what-we-can-do-better" tabindex="-1">What we can do better <a class="header-anchor" href="#what-we-can-do-better" aria-label="Permalink to &quot;What we can do better&quot;">​</a></h2><p>While a lot went well, we can always do better. We hope to have official NeoNephos Ambassadors present at next year&#39;s event. Ideally, these Ambassadors have a background from a diverse set of organizations and companies. <a href="https://neonephos.org/outreach_committee" target="_blank" rel="noreferrer">Thanks to our newly formed Outreach Committee</a>, which manages this program, we believe this wish is within reach.</p><h2 id="the-future" tabindex="-1">The future <a class="header-anchor" href="#the-future" aria-label="Permalink to &quot;The future&quot;">​</a></h2><p>If you have not been there, be sure to recap our talks at the official <a href="https://www.youtube.com/watch?v=hpwJs1DJAo4&amp;list=PLj6h78yzYM2MXCOWSN9CqqID6OOvF7wxL" target="_blank" rel="noreferrer">KubeCon + CloudNativeCon Europe 26 playlist</a>. Until then, discuss with us the future by chatting with us on <a href="https://linuxfoundation.zulipchat.com/#narrow/channel/525732-neonephos-discussion/topic/channel.20events/with/558483910" target="_blank" rel="noreferrer">Zulip</a>. See you there!</p>',10)]))}const b=o(r,[["render",s]]);export{d as __pageData,b as default};
